    48→
    49→const STRIPE_ELEMENT_STYLE = {
    50→  style: {
    51→    base: {
    52→      fontSize: "14px",
    53→      fontFamily: "DM Sans, sans-serif",
    54→      color: "#44403C",
    55→      "::placeholder": { color: "#A8A29E" },
    56→    },
    57→    invalid: { color: "#ef4444" },
    58→  },
    59→};
    60→
    61→type PaymentTab = "card" | "crypto";
    62→
    63→type SelectedMethod =
    64→  | { type: "stripe-new" }
    65→  | { type: "stripe-saved"; id: string; last4: string; brand?: string }
    66→  | { type: "paypal-new" }
    67→  | { type: "paypal-saved"; id: string; email: string };
    68→
    69→type PaymentStep = "select" | "processing" | "success";
    70→
    71→interface CardFormValues {
    72→  cardholderName: string;
    73→  saveCard: boolean;
    74→  acceptTerms: boolean;
    75→}
    76→
    77→interface BuybackPaymentFormProps {
    78→  buybackId: string;
    79→}
    80→
    81→function BuybackPaymentForm({ buybackId }: BuybackPaymentFormProps) {
    82→  const router = useRouter();
    83→  const stripe = useStripe();
    84→  const elements = useElements();
    85→  const queryClient = useQueryClient();
    86→  const searchParams = useSearchParams();
    87→
    88→  const { data: buyback, isLoading: buybackLoading } = useBuybackDetails(
    89→    buybackId,
    90→    true,
    91→  );
    92→  const { balance: walletBalance } = useWalletBalance();
    93→  const { data: stripeMethods } = useStripeMethods();
    94→  const { data: paypalMethods } = usePayPalMethods();
    95→
    96→  const createPayment = useCreatePayment();
    97→  const createPaymentIntent = useCreatePaymentIntent();
    98→  const createPayPalCheckoutSession = useCreatePayPalCheckoutSession();
    99→  const completeBuyback = useCompleteBuyback();
   100→
   101→  const isPayPalReturn = searchParams.get("paypal_return") === "success";
   102→  const paypalReturnPaymentId = searchParams.get("payment_id");
   103→
   104→  const [tab, setTab] = useState<PaymentTab>("card");
   105→  const [step, setStep] = useState<PaymentStep>(
   106→    isPayPalReturn ? "processing" : "select",
   107→  );
   108→  const [selectedMethod, setSelectedMethod] = useState<SelectedMethod>({
   109→    type: "stripe-new",
   110→  });
   111→  const [cardError, setCardError] = useState<string | null>(null);
   112→  const [isProcessing, setIsProcessing] = useState(isPayPalReturn);
   113→  const submittedRef = useRef(false);
   114→  const paypalHandledRef = useRef(false);
   115→
   116→  const { register, watch, setValue } = useForm<CardFormValues>({
   117→    defaultValues: { cardholderName: "", saveCard: true, acceptTerms: false },
   118→  });
   119→
   120→  const cardholderName = watch("cardholderName");
   121→  const saveCard = watch("saveCard");
   122→  const acceptTerms = watch("acceptTerms");
   123→
   124→  const outstandingCents =
   125→    buyback?.computedDetails?.outstandingAmountCents ?? 0;
   126→  const hasSufficientBalance = walletBalance >= outstandingCents;
   127→  const shortfallCents = hasSufficientBalance
   128→    ? 0
   129→    : outstandingCents - walletBalance;
   130→
   131→  // Poll GET /payments/:id until webhook is processed (status = SUCCEEDED/FAILED)
   132→  const pollPaymentStatus = useCallback(async (paymentId: string): Promise<boolean> => {
   133→    for (let attempt = 0; attempt < 30; attempt += 1) {
   134→      const payment = await paymentService.getPayment(paymentId);
   135→
   136→      if (payment.status === PaymentStatus.SUCCEEDED) {
   137→        await queryClient.invalidateQueries({ queryKey: ApiKeys.wallet() });
   138→        return true;
   139→      }
   140→
   141→      if (
   142→        payment.status === PaymentStatus.FAILED ||
   143→        payment.status === PaymentStatus.CANCELED ||
   144→        payment.status === PaymentStatus.EXPIRED
   145→      ) {
   146→        return false;
   147→      }
   148→
   149→      await new Promise((resolve) => setTimeout(resolve, 1000));
   150→    }
   151→
   152→    return false;
   153→  }, [queryClient]);
   154→
   155→  useEffect(() => {
   156→    if (
   157→      !(isPayPalReturn &&paypalReturnPaymentId ) ||
   158→      paypalHandledRef.current ||
   159→      buybackLoading ||
   160→      !buyback
   161→    )
   162→      return;
   163→
   164→    paypalHandledRef.current = true;
   165→    setIsProcessing(true);
   166→    setStep("processing");
   167→
   168→    pollPaymentStatus(paypalReturnPaymentId)
   169→      .then((succeeded) => {
   170→        if (!succeeded) {
   171→          toast.error("Payment was not completed. Please try again.");
   172→          setStep("select");
   173→          setIsProcessing(false);
   174→          return ;
   175→        }
   176→        return completeBuyback.mutateAsync(buybackId);
   177→      })
   178→      .then((result) => {
   179→        if (result !== undefined) {
   180→          setStep("success");
   181→        }
   182→      })
   183→      .catch((error: unknown) => {
   184→        setStep("select");
   185→        const axiosError = error as AxiosError<{ message?: string }>;
   186→        toast.error(
   187→          axiosError.response?.data?.message ??
   188→            "Payment failed. Please try again.",
   189→        );
   190→      })
   191→      .finally(() => {
   192→        setIsProcessing(false);
   193→        submittedRef.current = false;
   194→      });
   195→  }, [buyback, buybackId, buybackLoading, completeBuyback, isPayPalReturn, paypalReturnPaymentId, pollPaymentStatus]);
   196→
   197→  async function handleCompletePayment() {
   198→    if (submittedRef.current || isProcessing) return;
   199→
   200→    if (!acceptTerms) {
   201→      toast.error("Please accept the LuxFlow Terms of Use to continue");
   202→      return;
   203→    }
   204→
   205→    submittedRef.current = true;
   206→    setIsProcessing(true);
   207→    setCardError(null);
   208→
   209→    try {
   210→      if (hasSufficientBalance) {
   211→        setStep("processing");
   212→        await completeBuyback.mutateAsync(buybackId);
   213→        setStep("success");
   214→        return;
   215→      }
   216→
   217→      const topUpAmountDollars = centsToDollars(shortfallCents);
   218→
   219→      if (
   220→        selectedMethod.type === "paypal-new" ||
   221→        selectedMethod.type === "paypal-saved"
   222→      ) {
   223→        const payment = await createPayment.mutateAsync({
   224→          purpose: PaymentPurpose.DEPOSIT,
   225→          walletAmount: topUpAmountDollars,
   226→          currency: "USD",
   227→          method: paymentMethodMap.paypal,
   228→          idempotencyKey: `buyback_${buybackId}_${Date.now()}`,
   229→        });
   230→
   231→        const payPageUrl = `${window.location.origin}${APP_ROUTES.BUYBACKS.PAY(buybackId)}`;
   232→        const session = await createPayPalCheckoutSession.mutateAsync({
   233→          paymentId: payment.id,
   234→          paymentMethodId:
   235→            selectedMethod.type === "paypal-saved"
   236→              ? selectedMethod.id
   237→              : undefined,
   238→          returnUrl: `${payPageUrl}?paypal_return=success&payment_id=${payment.id}`,
   239→          cancelUrl: payPageUrl,
   240→        });
   241→
   242→        if (!session.url) throw new Error("Missing PayPal checkout URL");
   243→        window.location.href = session.url;
   244→        return;
   245→      }
   246→
   247→      if (!(stripe && elements)) {
   248→        toast.error("Payment system not loaded. Please refresh.");
   249→        return;
   250→      }
   251→
   252→      const payment = await createPayment.mutateAsync({
   253→        purpose: PaymentPurpose.DEPOSIT,
   254→        walletAmount: topUpAmountDollars,
   255→        currency: "USD",
   256→        method: paymentMethodMap.stripe,
   257→        idempotencyKey: `buyback_${buybackId}_${Date.now()}`,
   258→      });
   259→
   260→      const intentData = await createPaymentIntent.mutateAsync({
   261→        paymentId: payment.id,
   262→        savedMethodId:
   263→          selectedMethod.type === "stripe-saved"
   264→            ? selectedMethod.id
   265→            : undefined,
   266→      });
   267→
   268→      let confirmResult:
   269→        | Awaited<ReturnType<typeof stripe.confirmCardPayment>>
   270→        | undefined;
   271→
   272→      if (selectedMethod.type === "stripe-saved") {
   273→        confirmResult = await stripe.confirmCardPayment(
   274→          intentData.clientSecret,
   275→          { payment_method: selectedMethod.id },
   276→        );
   277→      } else {
   278→        const cardNumberElement = elements.getElement(CardNumberElement);
   279→        if (!cardNumberElement) throw new Error("Card element not found");
   280→
   281→        confirmResult = await stripe.confirmCardPayment(
   282→          intentData.clientSecret,
   283→          {
   284→            payment_method: {
   285→              card: cardNumberElement,
   286→              billing_details: { name: cardholderName },
   287→            },
   288→            setup_future_usage: saveCard ? "off_session" : undefined,
   289→          },
   290→        );
   291→      }
   292→
   293→      if (confirmResult?.error) {
   294→        setCardError(confirmResult.error.message ?? "Card payment failed");
   295→        return;
   296→      }
   297→
   298→      setStep("processing");
   299→
   300→      const paymentSucceeded = await pollPaymentStatus(payment.id);
