export enum PaymentPurpose {
  DEPOSIT = "DEPOSIT",
  FEE = "FEE",
  WITHDRAWAL_FEE = "WITHDRAWAL_FEE",
}

export enum PaymentProvider {
  STRIPE = "stripe",
  CRYPTO = "crypto",
  PAYPAL = "paypal",
}

export enum PaymentMethod {
  STRIPE_CARD = "STRIPE_CARD",
  STRIPE_BANK = "STRIPE_BANK",
  PAYPAL_ACCOUNT = "PAYPAL_ACCOUNT",
  PAYPAL_BANK = "PAYPAL_BANK",
  BINANCE_PAY_CRYPTO = "BINANCE_PAY_CRYPTO",
  CRYPTO_USDT_TRC20 = "CRYPTO_USDT_TRC20",
  INTERNAL_WALLET = "INTERNAL_WALLET",
}

export const paymentMethodMap: Record<string, PaymentMethod> = {
  paypal: PaymentMethod.PAYPAL_BANK,
  stripe: PaymentMethod.STRIPE_CARD,
  wallet: PaymentMethod.INTERNAL_WALLET,
  crypto: PaymentMethod.CRYPTO_USDT_TRC20,
  binance: PaymentMethod.BINANCE_PAY_CRYPTO,
};

export enum PaymentStatus {
  CREATED = "CREATED",
  PENDING = "PENDING",
  SUCCEEDED = "SUCCEEDED",
  FAILED = "FAILED",
  CANCELED = "CANCELED",
  EXPIRED = "EXPIRED",
}

export interface Payment {
  id: string;
  userId: string;
  purpose: PaymentPurpose;
  method: PaymentMethod;
  provider: PaymentProvider;
  status: PaymentStatus;
  amountSubtotal: number;
  feeAmount: number;
  taxAmount: number;
  amountTotal: number;
  currency: string;
  providerRef?: string;
  expiresAt: string;
  createdAt: string;
  updatedAt: string;
}

export interface CreatePaymentRequest {
  purpose: PaymentPurpose;
  walletAmount?: number; // Optional for FEE
  amountTotal?: number; // Required for FEE
  taxAmount?: number; // Optional for FEE
  method?: PaymentMethod; // Required for FEE
  currency?: string;
  idempotencyKey?: string;
}

export interface CreatePaymentResponse extends Payment {}

export interface PaymentListResponse {
  items: Payment[];
  total: number;
  skip: number;
  limit: number;
}

export interface CreateCheckoutSessionRequest {
  paymentId: string;
  savedMethodId?: string;
}

export interface CreateCheckoutSessionResponse {
  url: string;
  sessionId: string;
}

export interface SetupIntentResponse {
  clientSecret: string;
  setupIntentId: string;
}

export enum SavedMethodType {
  CARD = "CARD",
  BANK_ACCOUNT = "BANK_ACCOUNT",
}

export interface SavedStripeMethod {
  id: string;
  type: SavedMethodType;
  last4: string;
  brand?: string;
  expiryMonth?: number;
  expiryYear?: number;
  isDefault: boolean;
  nickname?: string;
  createdAt: string;
  updatedAt: string;
}

export interface CreateStripeMethodRequest {
  setupIntentId: string;
  nickname?: string;
  setAsDefault?: boolean;
}

export interface UpdateStripeMethodRequest {
  nickname?: string;
  setAsDefault?: boolean;
}

export enum PayPalMethodType {
  PAYPAL_ACCOUNT = "PAYPAL_ACCOUNT",
  PAYPAL_BANK = "PAYPAL_BANK",
}

export interface PayPalMethod {
  id: string;
  walletId: string;
  paypalPaymentTokenId: string;
  paypalCustomerId: string | null;
  type: PayPalMethodType;
  email: string;
  isDefault: boolean;
  nickname: string | null;
  createdAt: string;
  updatedAt: string;
}

export interface PayPalSetupIntentResponse {
  approvalUrl: string;
  setupTokenId: string;
}

export interface CreatePayPalMethodRequest {
  setupTokenId: string;
  nickname?: string;
  setAsDefault?: boolean;
}

export interface UpdatePayPalMethodRequest {
  nickname?: string;
  setAsDefault?: boolean;
}

export interface CreatePaymentIntentRequest {
  paymentId: string;
  savedMethodId?: string;
}

export interface CreatePaymentIntentResponse {
  clientSecret: string;
  paymentIntentId: string;
}

export interface CreatePayPalCheckoutSessionRequest {
  paymentId: string;
  paymentMethodId?: string;
  returnUrl?: string;
  cancelUrl?: string;
}

export interface CreatePayPalCheckoutSessionResponse {
  url: string;
  sessionId: string;
}

export enum CryptoNetwork {
  TRON = "TRON",
}

export interface SavedCryptoAddress {
  id: string;
  network: CryptoNetwork;
  address: string;
  label: string;
  isDefault: boolean;
  createdAt: string;
  updatedAt: string;
}

export interface CreateCryptoAddressRequest {
  network: CryptoNetwork;
  address: string;
  label: string;
  setAsDefault?: boolean;
}

export interface UpdateCryptoAddressRequest {
  label?: string;
  setAsDefault?: boolean;
}

export interface Wallet {
  balance: number;
  balanceDollars: number;
  currency: string;
  lastActivityAt?: string;
}

export enum TransactionDirection {
  CREDIT = "CREDIT",
  DEBIT = "DEBIT",
}

export enum TransactionType {
  DEPOSIT = "deposit",
  BUYBACK_REPAYMENT = "buyback_repayment",
  LOAN_DISBURSEMENT = "loan_disbursement",
  FEE_PAYMENT = "fee_payment",
}

export interface WalletTransaction {
  id: string;
  type: TransactionType;
  status: "completed" | "pending" | "failed";
  description: string;
  amountTotal: number;
  amountTotalDollars: number;
  currency: string;
  createdAt: string;
  userEntry: {
    direction: TransactionDirection;
    amount: number;
    amountDollars: number;
  };
  paymentMethod?: {
    type: "card" | "bank_account" | "wallet";
    displayName: string;
    brand?: string;
    last4?: string;
  };
  fees?: {
    stripeFee?: number;
    serviceFee?: number;
    vat?: number;
  };
}

export interface WalletTransactionsResponse {
  data: WalletTransaction[];
  total: number;
  skip: number;
  limit: number;
}

export interface InsufficientBalanceError {
  statusCode: number;
  error: "INSUFFICIENT_BALANCE";
  message: string;
  details: {
    currentBalance: number;
    requiredAmount: number;
    shortfall: number;
    recommendedTopUp: number;
  };
}

export interface InvalidAddressError {
  statusCode: number;
  error: "INVALID_TRON_ADDRESS";
  message: string;
}

export interface DuplicateAddressError {
  statusCode: number;
  error: "DUPLICATE_ADDRESS";
  message: string;
}

export enum TransactionUseFor {
  BUYBACK_REPAYMENT = "BUYBACK_REPAYMENT",
  WALLET_DEPOSIT = "WALLET_DEPOSIT",
  WALLET_WITHDRAWAL = "WALLET_WITHDRAWAL",
  PLATFORM_FEE = "PLATFORM_FEE",
  REFUND = "REFUND",
  ADJUSTMENT = "ADJUSTMENT",
  AUCTION_DEPOSIT = "AUCTION_DEPOSIT",
  RETAIL_ASSETS = "RETAIL_ASSETS",
  POINTS = "POINTS",
  TICKET = "TICKET",
}

export enum LedgerTransactionType {
  DEPOSIT = "DEPOSIT",
  WITHDRAWAL = "WITHDRAWAL",
  FEE = "FEE",
  REFUND = "REFUND",
  LOAN_DISBURSEMENT = "LOAN_DISBURSEMENT",
  LOAN_REPAYMENT = "LOAN_REPAYMENT",
  ADJUSTMENT = "ADJUSTMENT",
}

export interface AdminPaymentTransaction {
  id: string;
  user: {
    id: string;
    email: string;
    fullName: string;
  };
  buybackId: string | null;
  auctionId: string | null;
  asset: {
    id: string;
    name: string;
    photos: string[];
  } | null;
  amountCents: number;
  amountDollars: number;
  currency: string;
  transactionHash: string | null;
  paymentMethod: PaymentMethod | null;
  status: PaymentStatus;
  transactionType: LedgerTransactionType;
  createdAt: string;
  updatedAt: string;
}

export interface AdminPaymentsFilters {
  skip?: number;
  take?: number;
  order?: "ASC" | "DESC";
  orderBy?: "createdAt" | "updatedAt";
  search?: string;
  userIds?: string[];
  categories?: string[];
  brands?: string[];
  transactionTypes?: LedgerTransactionType[];
  paymentMethods?: PaymentMethod[];
  paymentStatuses?: PaymentStatus[];
  startDate?: string;
  endDate?: string;
}

export interface AdminPaymentsResponse {
  total: number;
  data: AdminPaymentTransaction[];
  skip: number;
  take: number;
}

export interface LifetimePaymentsReceivedDto {
  amount: number;
  amountDollars: number;
  currency: string;
}

export interface WalletTransactionsSummaryResponseDto {
  lifetimePermanentSaleOffers: number;
  lifetimeCompletedBuybackOffers: number;
  allTimeDeclinedOrExpiredOffers: number;
  lifetimePaymentsReceived: LifetimePaymentsReceivedDto;
}

export const CRYPTO_NETWORK_LABELS: Record<CryptoNetwork, string> = {
  TRON: "TRC-20",
};

