     2→import { API_ROUTES } from "@/shared/config/api-routes";
     3→import type {
     4→  CreateCheckoutSessionRequest,
     5→  CreateCheckoutSessionResponse,
     6→  CreatePaymentIntentRequest,
     7→  CreatePaymentIntentResponse,
     8→  CreatePaymentRequest,
     9→  CreatePaymentResponse,
    10→  Payment,
    11→  PaymentListResponse,
    12→} from "@/shared/types/payment.types";
    13→
    14→export const paymentService = {
    15→  async createPayment(
    16→    request: CreatePaymentRequest,
    17→  ): Promise<CreatePaymentResponse> {
    18→    const api = await getApi();
    19→
    20→    // For FEE payments, use amountTotal instead of walletAmount
    21→    const payload =
    22→      request.purpose === "FEE"
    23→        ? {
    24→            purpose: request.purpose,
    25→            amountTotal: request.amountTotal,
    26→            taxAmount: request.taxAmount,
    27→            method: request.method,
    28→            currency: request.currency,
    29→            idempotencyKey: request.idempotencyKey,
    30→          }
    31→        : {
    32→            purpose: request.purpose,
    33→            walletAmount: request.walletAmount,
    34→            method: request.method,
    35→            currency: request.currency,
    36→            idempotencyKey: request.idempotencyKey,
    37→          };
    38→
    39→    const { data } = await api.post<CreatePaymentResponse>(
    40→      API_ROUTES.PAYMENTS.CREATE,
    41→      payload,
    42→      {
    43→        headers: request.idempotencyKey
    44→          ? { "Idempotency-Key": request.idempotencyKey }
    45→          : undefined,
    46→      },
    47→    );
    48→
    49→    return data;
