import { getApi } from "@/shared/api/api";
import { API_ROUTES } from "@/shared/config/api-routes";
import type {
  CreateCheckoutSessionRequest,
  CreateCheckoutSessionResponse,
  CreatePaymentIntentRequest,
  CreatePaymentIntentResponse,
  CreatePaymentRequest,
  CreatePaymentResponse,
  Payment,
  PaymentListResponse,
} from "@/shared/types/payment.types";

export const paymentService = {
  async createPayment(
    request: CreatePaymentRequest,
  ): Promise<CreatePaymentResponse> {
    const api = await getApi();

    // For FEE payments, use amountTotal instead of walletAmount
    const payload =
      request.purpose === "FEE"
        ? {
            purpose: request.purpose,
            amountTotal: request.amountTotal,
            taxAmount: request.taxAmount,
            method: request.method,
            currency: request.currency,
            idempotencyKey: request.idempotencyKey,
          }
        : {
            purpose: request.purpose,
            walletAmount: request.walletAmount,
            method: request.method,
            currency: request.currency,
            idempotencyKey: request.idempotencyKey,
          };

    const { data } = await api.post<CreatePaymentResponse>(
      API_ROUTES.PAYMENTS.CREATE,
      payload,
      {
        headers: request.idempotencyKey
          ? { "Idempotency-Key": request.idempotencyKey }
          : undefined,
      },
    );

    return data;
  },

  async getPayment(id: string): Promise<Payment> {
    const api = await getApi();

    const { data } = await api.get<Payment>(API_ROUTES.PAYMENTS.GET(id));

    return data;
  },

  async listPayments(params?: {
    limit?: number;
    skip?: number;
  }): Promise<PaymentListResponse> {
    const api = await getApi();

    const { data } = await api.get<PaymentListResponse>(
      API_ROUTES.PAYMENTS.LIST,
      { params },
    );

    return data;
  },

  async createCheckoutSession(
    request: CreateCheckoutSessionRequest,
  ): Promise<CreateCheckoutSessionResponse> {
    const api = await getApi();

    const { data } = await api.post<CreateCheckoutSessionResponse>(
      API_ROUTES.STRIPE_CHECKOUT,
      request,
    );

    return data;
  },

  async createPaymentIntent(
    request: CreatePaymentIntentRequest,
  ): Promise<CreatePaymentIntentResponse> {
    const api = await getApi();

    const { data } = await api.post<CreatePaymentIntentResponse>(
      API_ROUTES.STRIPE_PAYMENT_INTENT,
      request,
    );

    return data;
  },
};

