import { getErrorMessage } from "@/shared/types/api-error.types";
import type {
  CreateCheckoutSessionRequest,
  CreatePayPalCheckoutSessionRequest,
  CreatePaymentIntentRequest,
  CreatePaymentRequest,
} from "@/shared/types/payment.types";
import { toast } from "@/shared/ui/notification";
import { useMutation } from "@tanstack/react-query";
import { paymentService } from "../services/payment.service";
import { paypalCheckoutService } from "../services/paypal-checkout.service";

export function useCreatePayment() {
  return useMutation({
    mutationFn: (data: CreatePaymentRequest) =>
      paymentService.createPayment(data),
    onError: (error: unknown) => {
      toast.error(getErrorMessage(error, "Failed to create payment"));
    },
  });
}

export function useCreateCheckoutSession() {
  return useMutation({
    mutationFn: (data: CreateCheckoutSessionRequest) =>
      paymentService.createCheckoutSession(data),
    onError: (error: unknown) => {
      toast.error(getErrorMessage(error, "Failed to create checkout session"));
    },
  });
}

export function useCreatePaymentIntent() {
  return useMutation({
    mutationFn: (data: CreatePaymentIntentRequest) =>
      paymentService.createPaymentIntent(data),
    onError: (error: unknown) => {
      toast.error(getErrorMessage(error, "Failed to initialize payment"));
    },
  });
}

export function useCreatePayPalCheckoutSession() {
  return useMutation({
    mutationFn: (data: CreatePayPalCheckoutSessionRequest) =>
      paypalCheckoutService.createCheckoutSession(data),
    onError: (error: unknown) => {
      toast.error(
        getErrorMessage(error, "Failed to create PayPal checkout session")
      );
    },
  });
}

