import { getApi } from "@/shared/api/api";
import { API_ROUTES } from "@/shared/config/api-routes";
import type {
  CreateCryptoAddressRequest,
  SavedCryptoAddress,
  UpdateCryptoAddressRequest,
} from "@/shared/types/payment.types";

export const cryptoAddressesService = {
  async createAddress(
    request: CreateCryptoAddressRequest,
  ): Promise<SavedCryptoAddress> {
    const api = await getApi();

    const { data } = await api.post<SavedCryptoAddress>(
      API_ROUTES.CRYPTO_ADDRESSES.CREATE,
      request,
    );
    return data;
  },

  async listAddresses(): Promise<SavedCryptoAddress[]> {
    const api = await getApi();

    const { data } = await api.get<SavedCryptoAddress[]>(
      API_ROUTES.CRYPTO_ADDRESSES.LIST,
    );

    return data;
  },

  async getAddress(id: string): Promise<SavedCryptoAddress> {
    const api = await getApi();

    const { data } = await api.get<SavedCryptoAddress>(
      API_ROUTES.CRYPTO_ADDRESSES.GET(id),
    );

    return data;
  },

  async updateAddress(
    id: string,
    request: UpdateCryptoAddressRequest,
  ): Promise<SavedCryptoAddress> {
    const api = await getApi();

    const { data } = await api.patch<SavedCryptoAddress>(
      API_ROUTES.CRYPTO_ADDRESSES.UPDATE(id),
      request,
    );

    return data;
  },

  async deleteAddress(id: string): Promise<void> {
    const api = await getApi();

    await api.delete(API_ROUTES.CRYPTO_ADDRESSES.DELETE(id));
  },
};

