"use client";

import { formatDollarsToUSD } from "@/shared/lib/utils/price-formatter";
import { zodResolver } from "@hookform/resolvers/zod";
import { useEffect, useState } from "react";
import { useForm } from "react-hook-form";
import { z } from "zod";

import {
  useCreateCheckoutSession,
  useCreatePayment,
  useCreatePayPalCheckoutSession,
} from "@/shared/api/query-hooks/use-payments";
import { usePayPalMethods } from "@/shared/api/query-hooks/use-paypal-methods";
import { useWalletInfo } from "@/shared/api/query-hooks/use-wallet";
import { paymentMethodMap, PaymentPurpose } from "@/shared/types/payment.types";
import { Badge } from "@/shared/ui/badge";
import { Button } from "@/shared/ui/button";
import {
  Dialog,
  DialogCloseButton,
  DialogContent,
  DialogTitle,
} from "@/shared/ui/dialog";
import { Form } from "@/shared/ui/form/form";
import { FormControl } from "@/shared/ui/form/form-control";
import { FormField } from "@/shared/ui/form/form-field";
import { FormItem } from "@/shared/ui/form/form-item";
import { FormMessage } from "@/shared/ui/form/form-message";
import { Input } from "@/shared/ui/input";
import { Label } from "@/shared/ui/label";
import { toast } from "@/shared/ui/notification";
import { RadioGroup, RadioGroupItem } from "@/shared/ui/radio";
import { AxiosError } from "axios";

const depositSchema = z.object({
  amount: z
    .string()
    .min(1, "Amount is required")
    .refine(
      (val) => !Number.isNaN(Number(val)) && Number(val) >= 10,
      "Minimum deposit is $10.00",
    ),
  method: z.enum(["stripe", "paypal", "crypto"]),
  savedPayPalMethodId: z.string().optional(),
});

type DepositForm = z.infer<typeof depositSchema>;

interface DepositFundsModalProps {
  isOpen: boolean;
  onClose: () => void;
  suggestedAmount?: number;
}

export function DepositFundsModal({
  isOpen,
  onClose,
  suggestedAmount,
}: DepositFundsModalProps) {
  const { data: walletInfo } = useWalletInfo();
  const { data: paypalMethods } = usePayPalMethods();
  const createPayment = useCreatePayment();
  const createCheckoutSession = useCreateCheckoutSession();
  const createPayPalCheckoutSession = useCreatePayPalCheckoutSession();
  const [isProcessing, setIsProcessing] = useState(false);

  const form = useForm<DepositForm>({
    resolver: zodResolver(depositSchema),
    defaultValues: {
      amount: suggestedAmount ? suggestedAmount.toFixed(2) : "",
      method: "stripe",
      savedPayPalMethodId: undefined,
    },
  });

  const amount = form.watch("amount");
  const method = form.watch("method");

  useEffect(() => {
    if (isOpen && suggestedAmount) {
      form.reset({
        amount: suggestedAmount.toFixed(2),
        method: "stripe",
      });
    }
  }, [isOpen, suggestedAmount, form]);

  async function handleDeposit(data: DepositForm) {
    if (isProcessing) return;

    try {
      setIsProcessing(true);

      const payment = await createPayment.mutateAsync({
        purpose: PaymentPurpose.DEPOSIT,
        walletAmount: Number(data.amount),
        currency: "USD",
        method: paymentMethodMap[data.method],
        idempotencyKey: `deposit_${Date.now()}_${Math.random().toString(36).substring(7)}`,
      });

      if (data.method === "paypal") {
        const checkoutSession = await createPayPalCheckoutSession.mutateAsync({
          paymentId: payment.id,
          paymentMethodId: data.savedPayPalMethodId,
        });

        if (!checkoutSession.url) {
          throw new Error("Missing PayPal checkout URL");
        }

        window.location.href = checkoutSession.url;
      } else {
        const checkoutSession = await createCheckoutSession.mutateAsync({
          paymentId: payment.id,
        });

        if (!checkoutSession.url) {
          throw new Error("Missing Stripe checkout URL");
        }

        window.location.href = checkoutSession.url;
      }
    } catch (error: unknown) {
      toast.error(
        error instanceof AxiosError
          ? error.response?.data?.message
          : "Failed to start deposit process",
      );
      setIsProcessing(false);
    }
  }

  if (!walletInfo) return null;

  const isValidAmount = amount && Number(amount) >= 10;
  const isCardOrPaypal = method === "stripe" || method === "paypal";

  const estimatedFee =
    isValidAmount && isCardOrPaypal ? Number(amount) * 0.029 + 0.3 : 0;
  const estimatedTotal =
    isValidAmount && isCardOrPaypal ? Number(amount) + estimatedFee : 0;

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-h-[95vh] w-[calc(100vw-2rem)] max-w-[600px] gap-0 p-4 sm:p-6 lg:p-[30px]">
        <div className="flex flex-col gap-4 sm:gap-6 lg:gap-[30px]">
          <div className="flex items-center justify-between">
            <DialogTitle className="font-bold font-serif text-foreground text-lg leading-[1.199em] sm:text-xl lg:text-2xl">
              Deposit Funds
            </DialogTitle>
            <DialogCloseButton />
          </div>

          <div className="flex flex-col gap-2 rounded-[10px] bg-secondary/10 p-3 sm:flex-row sm:items-center sm:justify-between sm:gap-4 sm:p-4">
            <span className="font-serif text-foreground text-sm sm:text-base">
              Current Balance
            </span>
            <div className="flex items-center gap-3 sm:gap-4">
              <span className="font-bold font-serif text-base text-foreground sm:text-lg">
                {walletInfo.usdtBalanceFormatted}
              </span>
              <span className="font-serif text-foreground text-sm sm:text-base">
                {walletInfo.balanceFormatted}
              </span>
            </div>
          </div>

          <Form {...form}>
            <form
              onSubmit={form.handleSubmit(handleDeposit)}
              className="flex flex-col gap-4 sm:gap-6 lg:gap-[30px]"
            >
              <div
                className="flex flex-col gap-4 overflow-y-auto pr-1 sm:gap-5 sm:pr-2 lg:gap-[25px]"
                style={{ maxHeight: "calc(95vh - 450px)" }}
              >
                <FormField
                  control={form.control}
                  name="method"
                  render={({ field }) => (
                    <FormItem className="flex flex-col gap-2">
                      <Label className="font-serif text-foreground text-sm leading-[1.375em] sm:text-base">
                        Payment Method
                      </Label>
                      <FormControl>
                        <RadioGroup
                          value={field.value}
                          onValueChange={field.onChange}
                          className="gap-2 sm:gap-3"
                        >
                          <label className="flex cursor-pointer items-center gap-2 rounded-[10px] border border-input p-3 transition-colors hover:bg-secondary/20 data-[selected=true]:border-primary sm:gap-3 sm:p-4">
                            <RadioGroupItem value="stripe" />
                            <div className="flex flex-1 flex-col gap-0.5 sm:gap-1">
                              <span className="font-bold font-serif text-foreground text-sm sm:text-base">
                                Stripe
                              </span>
                              <span className="font-serif text-muted-foreground text-xs sm:text-sm">
                                Pay securely with Stripe
                              </span>
                            </div>
                          </label>

                          <label className="flex cursor-pointer items-center gap-3 rounded-[10px] border border-input p-4 transition-colors hover:bg-secondary/20 data-[selected=true]:border-primary">
                            <RadioGroupItem value="paypal" />
                            <div className="flex flex-1 flex-col gap-1">
                              <span className="font-bold font-serif text-base text-foreground">
                                PayPal
                              </span>
                              <span className="font-serif text-muted-foreground text-sm">
                                Pay securely with PayPal
                              </span>
                            </div>
                          </label>

                          <label className="flex cursor-not-allowed items-center gap-2 rounded-[10px] border border-input bg-secondary/5 p-3 opacity-50 sm:gap-3 sm:p-4">
                            <RadioGroupItem value="crypto" disabled />
                            <div className="flex flex-1 flex-col gap-0.5 sm:gap-1">
                              <div className="flex items-center gap-2">
                                <span className="font-bold font-serif text-foreground text-sm sm:text-base">
                                  Crypto
                                </span>
                                <Badge
                                  variant="outline"
                                  className="h-fit px-1.5 py-0.5 text-[10px] sm:px-2 sm:text-xs"
                                >
                                  Coming Soon
                                </Badge>
                              </div>
                              <span className="font-serif text-muted-foreground text-xs sm:text-sm">
                                Pay with cryptocurrency (USDT)
                              </span>
                            </div>
                          </label>
                        </RadioGroup>
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="amount"
                  render={({ field, fieldState }) => (
                    <FormItem className="flex flex-col gap-2">
                      <Label className="font-serif text-foreground text-sm leading-[1.375em] sm:text-base">
                        Deposit Amount (USD)
                      </Label>
                      <FormControl>
                        <Input
                          {...field}
                          type="number"
                          step="0.01"
                          placeholder="Minimum $10.00"
                          className="rounded-input border-input px-input-200 py-input-100 font-serif text-sm leading-[1.2em]"
                          aria-invalid={!!fieldState.error}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                {method === "paypal" &&
                  paypalMethods &&
                  paypalMethods.length > 0 && (
                    <FormField
                      control={form.control}
                      name="savedPayPalMethodId"
                      render={({ field }) => (
                        <FormItem className="flex flex-col gap-2">
                          <Label className="font-serif text-base text-foreground leading-[1.375em]">
                            Select PayPal Method (Optional)
                          </Label>
                          <FormControl>
                            <RadioGroup
                              value={field.value || "new"}
                              onValueChange={(value) =>
                                field.onChange(
                                  value === "new" ? undefined : value,
                                )
                              }
                              className="gap-3"
                            >
                              <label className="flex cursor-pointer items-center gap-3 rounded-[10px] border border-input p-4 transition-colors hover:bg-secondary/20 data-[selected=true]:border-primary">
                                <RadioGroupItem value="new" />
                                <div className="flex flex-1 flex-col gap-1">
                                  <span className="font-bold font-serif text-base text-foreground">
                                    New PayPal Account
                                  </span>
                                  <span className="font-serif text-muted-foreground text-sm">
                                    Use a new PayPal account
                                  </span>
                                </div>
                              </label>
                              {paypalMethods.map((paypalMethod) => (
                                <label
                                  key={paypalMethod.id}
                                  className="flex cursor-pointer items-center gap-3 rounded-[10px] border border-input p-4 transition-colors hover:bg-secondary/20 data-[selected=true]:border-primary"
                                >
                                  <RadioGroupItem value={paypalMethod.id} />
                                  <div className="flex flex-1 flex-col gap-1">
                                    <span className="font-bold font-serif text-base text-foreground">
                                      {paypalMethod.nickname ||
                                        paypalMethod.email}
                                    </span>
                                    <span className="font-serif text-muted-foreground text-sm">
                                      {paypalMethod.email}
                                      {paypalMethod.isDefault && " (Default)"}
                                    </span>
                                  </div>
                                </label>
                              ))}
                            </RadioGroup>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  )}

                {isValidAmount && isCardOrPaypal && (
                  <div className="flex flex-col gap-2.5 rounded-[10px] border border-primary/20 bg-primary/5 p-3 sm:gap-3 sm:p-4">
                    <div className="flex justify-between gap-2">
                      <span className="font-serif text-foreground text-xs sm:text-sm">
                        Deposit to Wallet:
                      </span>
                      <span className="font-bold font-serif text-foreground text-xs sm:text-sm">
                        {formatDollarsToUSD(Number(amount))}
                      </span>
                    </div>
                    <div className="flex justify-between gap-2">
                      <span className="font-serif text-foreground text-xs sm:text-sm">
                        {`Estimated ${
                          method === "stripe" ? "Stripe" : "PayPal"
                        } Fee (2.9% + $0.30):`}
                      </span>
                      <span className="font-serif text-foreground text-xs sm:text-sm">
                        {formatDollarsToUSD(estimatedFee)}
                      </span>
                    </div>
                    <div className="h-px bg-primary/20" />
                    <div className="flex justify-between gap-2">
                      <span className="font-bold font-serif text-foreground text-sm sm:text-base">
                        Total to Pay:
                      </span>
                      <span className="font-bold font-serif text-foreground text-sm sm:text-base">
                        {formatDollarsToUSD(estimatedTotal)}
                      </span>
                    </div>
                    <p className="font-serif text-[10px] text-muted-foreground sm:text-xs">
                      {`* Final fees will be calculated by ${
                        method === "stripe" ? "Stripe" : "PayPal"
                      } at checkout`}
                    </p>
                  </div>
                )}

                {method === "stripe" && (
                  <div className="rounded-[10px] border border-primary/20 bg-primary/5 p-4">
                    <p className="font-serif text-foreground text-sm leading-[1.4em]">
                      You will be redirected to Stripe to complete your payment
                      securely.
                    </p>
                  </div>
                )}

                {method === "paypal" && (
                  <div className="rounded-[10px] border border-primary/20 bg-primary/5 p-4">
                    <p className="font-serif text-foreground text-sm leading-[1.4em]">
                      You will be redirected to PayPal to complete your payment
                      securely.
                    </p>
                  </div>
                )}
              </div>

              <Button
                type="submit"
                loading={isProcessing}
                disabled={
                  isProcessing ||
                  !amount ||
                  Number(amount) < 10 ||
                  method === "crypto"
                }
                className="h-auto w-full rounded-[15px] px-5 py-2.5 text-sm sm:px-[30px] sm:py-[10px] sm:text-base"
                size="default"
              >
                {isProcessing && "Processing..."}
                {!isProcessing &&
                  method === "crypto" &&
                  "Crypto Deposits Coming Soon"}
                {!isProcessing &&
                  method === "stripe" &&
                  "Continue to Stripe Checkout"}
                {!isProcessing &&
                  method === "paypal" &&
                  "Continue to PayPal Checkout"}
              </Button>
            </form>
          </Form>
        </div>
      </DialogContent>
    </Dialog>
  );
}

