import { getApi } from "@/shared/api/api";
import { API_ROUTES } from "@/shared/config/api-routes";
import type {
  CreatePayPalCheckoutSessionRequest,
  CreatePayPalCheckoutSessionResponse,
} from "@/shared/types/payment.types";

export const paypalCheckoutService = {
  async createCheckoutSession(
    request: CreatePayPalCheckoutSessionRequest
  ): Promise<CreatePayPalCheckoutSessionResponse> {
    const api = await getApi();
    const { data } = await api.post<CreatePayPalCheckoutSessionResponse>(
      API_ROUTES.PAYPAL_CHECKOUT,
      request
    );
    return data;
  },
};

