"use client";

import { useEffect, useState } from "react";
import { QRCodeSVG } from "qrcode.react";
import { Copy, Check, X } from "lucide-react";
import { usePaymentPolling } from "@/shared/lib/hooks/use-payment-polling";
import type { CreateNowPaymentsCheckoutResponse } from "@/shared/types/payment.types";
import { Dialog, DialogContent, DialogTitle } from "@/shared/ui/dialog";
import { toast } from "@/shared/ui/notification";

interface NowPaymentsModalProps {
  isOpen: boolean;
  onClose: () => void;
  checkoutSession: CreateNowPaymentsCheckoutResponse;
  internalPaymentId: string;
  onSuccess?: () => void;
}

export function NowPaymentsModal({
  isOpen,
  onClose,
  checkoutSession,
  internalPaymentId,
  onSuccess,
}: NowPaymentsModalProps) {
  const [copied, setCopied] = useState(false);
  const [confirmations, setConfirmations] = useState<number>(0);

  const { payment } = usePaymentPolling(isOpen ? internalPaymentId : null, {
    interval: 8000, // Increased from 3s to 8s to avoid rate limiting
    maxInterval: 30_000, // Max 30 seconds with exponential backoff
    enabled: isOpen,
    onSuccess: () => {
      toast.success("✅ Deposit successfully credited to your wallet!");
      setTimeout(() => {
        onSuccess?.();
        onClose();
      }, 2000);
    },
    onFailure: (failedPayment) => {
      if (failedPayment.status === "EXPIRED") {
        toast.error("⏰ Payment time expired. Please try again.");
      } else {
        toast.error("❌ Payment failed. Please contact support.");
      }
    },
  });

  useEffect(() => {
    if (payment?.metadata?.confirmations) {
      setConfirmations(payment.metadata.confirmations as number);
    }
  }, [payment]);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(checkoutSession.payAddress);
      setCopied(true);
      toast.success("Address copied to clipboard!");
      setTimeout(() => setCopied(false), 2000);
    } catch (_error) {
      toast.error("Failed to copy address");
    }
  };

  const getStatusInfo = () => {
    if (!payment) {
      return {
        text: "🟡 Waiting for payment...",
        color: "bg-yellow-50 text-yellow-700 border-yellow-200",
      };
    }

    switch (payment.status) {
      case "PENDING":
        if (confirmations > 0) {
          return {
            text: `🟡 Confirming in blockchain (${confirmations} confirmations)...`,
            color: "bg-yellow-50 text-yellow-700 border-yellow-200",
          };
        }
        return {
          text: "🟡 Payment received, waiting for blockchain confirmation...",
          color: "bg-yellow-50 text-yellow-700 border-yellow-200",
        };
      case "SUCCEEDED":
        return {
          text: "🟢 Payment completed successfully!",
          color: "bg-green-50 text-green-700 border-green-200",
        };
      case "FAILED":
        return {
          text: "🔴 Payment failed",
          color: "bg-red-50 text-red-700 border-red-200",
        };
      case "EXPIRED":
        return {
          text: "🔴 Payment expired",
          color: "bg-red-50 text-red-700 border-red-200",
        };
      default:
        return {
          text: "🟡 Waiting for payment...",
          color: "bg-yellow-50 text-yellow-700 border-yellow-200",
        };
    }
  };

  const statusInfo = getStatusInfo();

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-h-[calc(100vh-2rem)] w-[calc(100%-2rem)] max-w-[92vw] overflow-y-auto p-0 sm:max-h-[calc(100vh-3rem)] sm:max-w-[520px]">
        <div className="space-y-6 bg-card">
          {/* Header */}
          <div className="border-border border-b bg-gradient-to-r from-primary/10 via-card to-primary/10 px-4 py-4 sm:px-6 sm:py-5">
            <div className="flex items-center justify-between">
              <div>
                <DialogTitle className="font-bold font-serif text-[22px] tracking-tight">
                  Pay with Cryptocurrency
                </DialogTitle>
                <p className="mt-1 text-muted-foreground text-sm">
                  Scan or copy the address to complete your deposit.
                </p>
              </div>
              <button
                type="button"
                onClick={onClose}
                className="rounded-full p-2 text-muted-foreground transition-colors hover:bg-primary/10 hover:text-foreground"
              >
                <X className="h-5 w-5" />
              </button>
            </div>
          </div>

          <div className="space-y-6 px-4 pb-6 sm:px-6">
            {/* Status */}
            <div
              className={`flex items-center justify-center gap-2 rounded-full border px-4 py-2 text-center font-medium text-sm ${statusInfo.color}`}
            >
              <span className="h-2 w-2 rounded-full bg-current opacity-70" />
              {statusInfo.text}
            </div>

            {/* QR Code */}
            <div className="flex justify-center rounded-2xl border border-primary/15 bg-gradient-to-b from-card to-primary/5 p-5 shadow-sm sm:p-6">
              <div className="rounded-xl bg-card p-3 shadow-[0_10px_30px_rgba(16,24,40,0.08)]">
                <QRCodeSVG
                  value={`${checkoutSession.payAddress}?amount=${checkoutSession.payAmount}`}
                  size={256}
                  level="H"
                  includeMargin
                  className="h-44 w-44 sm:h-56 sm:w-56"
                />
              </div>
            </div>

            {/* Payment Details */}
            <div className="space-y-4">
              {/* Address */}
              <div className="rounded-xl border border-border bg-muted/30 p-4">
                <div className="mb-2 text-muted-foreground text-xs uppercase tracking-wide">
                  Payment Address
                </div>
                <div className="flex items-center gap-2">
                  <code className="flex-1 overflow-x-auto font-mono text-foreground text-sm">
                    {checkoutSession.payAddress}
                  </code>
                  <button
                    type="button"
                    onClick={handleCopy}
                    className="rounded-lg border border-transparent p-2 text-muted-foreground transition-colors hover:border-border hover:bg-card"
                    title="Copy address"
                  >
                    {copied ? (
                      <Check className="h-5 w-5 text-primary" />
                    ) : (
                      <Copy className="h-5 w-5" />
                    )}
                  </button>
                </div>
              </div>

              {/* Amount */}
              <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                <div className="rounded-xl border border-border bg-card p-4 shadow-sm">
                  <div className="mb-1 text-muted-foreground text-xs uppercase tracking-wide">
                    Amount
                  </div>
                  <div className="font-bold font-serif text-foreground text-lg">
                    {checkoutSession.payAmount} {checkoutSession.payCurrency}
                  </div>
                </div>

                <div className="rounded-xl border border-border bg-card p-4 shadow-sm">
                  <div className="mb-1 text-muted-foreground text-xs uppercase tracking-wide">
