                    ${checkoutSession.priceAmount} {checkoutSession.priceCurrency}
                  </div>
                </div>
              </div>
            </div>

            {/* Instructions */}
            <div className="space-y-2 rounded-xl border border-primary/15 bg-primary/5 p-4 text-foreground text-sm">
              <p className="font-medium">Instructions</p>
              <ol className="list-inside list-decimal space-y-1 text-foreground/80">
                <li>Scan the QR code or copy the address</li>
                <li>
                  Send{" "}
                  <strong>
                    exactly {checkoutSession.payAmount}{" "}
                    {checkoutSession.payCurrency}
                  </strong>
                </li>
                <li>Wait for blockchain confirmation</li>
                <li>Funds will be automatically credited to your wallet</li>
              </ol>
            </div>

            {/* Warnings */}
            <div className="space-y-2 text-muted-foreground text-xs">
              <div className="flex items-center gap-2">
                <span className="h-1.5 w-1.5 rounded-full bg-muted-foreground/70" />
                Send exactly the specified amount
              </div>
              <div className="flex items-center gap-2">
                <span className="h-1.5 w-1.5 rounded-full bg-muted-foreground/70" />
                Use the correct network ({checkoutSession.payCurrency})
              </div>
              <div className="flex items-center gap-2">
                <span className="h-1.5 w-1.5 rounded-full bg-muted-foreground/70" />
