"use client";

import { useEffect, useState } from "react";
import { paymentService } from "@/shared/api/services/payment.service";
import type { Payment } from "@/shared/types/payment.types";

interface PaymentPollingOptions {
  interval?: number;
  maxInterval?: number; // Maximum interval for exponential backoff
  onSuccess?: (payment: Payment) => void;
  onFailure?: (payment: Payment) => void;
  enabled?: boolean;
}

interface ErrorWithResponseStatus {
  response?: {
    status?: number;
  };
}

export function usePaymentPolling(
  paymentId: string | null,
  options: PaymentPollingOptions = {},
) {
  const {
    interval = 5000, // Increased from 3s to 5s
    maxInterval = 30_000, // Max 30 seconds
    onSuccess,
    onFailure,
    enabled = true,
  } = options;

  const [payment, setPayment] = useState<Payment | null>(null);
  const [error, setError] = useState<Error | null>(null);
  const [isPolling, setIsPolling] = useState(false);

  useEffect(() => {
    if (!(paymentId && enabled)) {
      return;
    }

    let pollTimeout: NodeJS.Timeout;
    let isMounted = true;
    let currentInterval = interval;
    let consecutiveErrors = 0;

    const poll = async () => {
      try {
        setIsPolling(true);
        const data = await paymentService.getPayment(paymentId);

        if (!isMounted) return;

        setPayment(data);
        consecutiveErrors = 0; // Reset error count on success

        // Check if payment is in a final state
        if (data.status === "SUCCEEDED") {
          setIsPolling(false);
          onSuccess?.(data);
          return; // Stop polling
        }

        if (data.status === "FAILED" || data.status === "EXPIRED") {
          setIsPolling(false);
          onFailure?.(data);
          return; // Stop polling
        }

        // Continue polling with current interval
        pollTimeout = setTimeout(poll, currentInterval);
      } catch (err) {
        if (!isMounted) return;

        const responseError = err as ErrorWithResponseStatus;
        // Check if it's a 429 error
        const is429Error = responseError.response?.status === 429;

        if (is429Error) {
          consecutiveErrors += 1;
          // Exponential backoff: double the interval on each 429, up to maxInterval
          currentInterval = Math.min(currentInterval * 2, maxInterval);
          console.warn(`Rate limited (429). Increasing poll interval to ${currentInterval}ms`);
        } else {
          consecutiveErrors = 0;
          currentInterval = interval; // Reset to normal interval for other errors
        }

        setError(err as Error);
        setIsPolling(false);

        // Continue polling even on error, but with adjusted interval
        if (consecutiveErrors < 10) { // Stop after 10 consecutive errors
          pollTimeout = setTimeout(poll, currentInterval);
        }
      }
    };

    // Initial poll
    poll();

    return () => {
      isMounted = false;
      clearTimeout(pollTimeout);
      setIsPolling(false);
    };
  }, [paymentId, interval, maxInterval, onSuccess, onFailure, enabled]);

  return { payment, error, isPolling };
}

