"use client";

import { useEffect, useState } from "react";
import { paymentService } from "@/shared/api/services/payment.service";
import type { Payment } from "@/shared/types/payment.types";

interface PaymentPollingOptions {
  interval?: number;
  maxInterval?: number;
  onSuccess?: (payment: Payment) => void;
  onFailure?: (payment: Payment) => void;
  enabled?: boolean;
}

interface ErrorWithResponseStatus {
  response?: {
    status?: number;
  };
}

export function usePaymentPolling(
  paymentId: string | null,
  options: PaymentPollingOptions = {},
) {
  const {
    interval = 5000,
    maxInterval = 30_000,
    onSuccess,
    onFailure,
    enabled = true,
  } = options;

  const [payment, setPayment] = useState<Payment | null>(null);
  const [error, setError] = useState<Error | null>(null);
  const [isPolling, setIsPolling] = useState(false);

  useEffect(() => {
    if (!(paymentId && enabled)) {
      return;
    }

    let pollTimeout: NodeJS.Timeout;
    let isMounted = true;
    let currentInterval = interval;
    let consecutiveErrors = 0;

    const poll = async () => {
      try {
        setIsPolling(true);
        const data = await paymentService.getPayment(paymentId);

        if (!isMounted) return;

        setPayment(data);
        consecutiveErrors = 0;
        currentInterval = interval;

        if (data.status === "SUCCEEDED") {
          setIsPolling(false);
          onSuccess?.(data);
          return;
        }

        if (data.status === "FAILED" || data.status === "EXPIRED" || data.status === "CANCELED") {
          setIsPolling(false);
          onFailure?.(data);
          return;
        }

        pollTimeout = setTimeout(poll, currentInterval);
      } catch (err) {
        if (!isMounted) return;

        const responseError = err as ErrorWithResponseStatus;
        const is429Error = responseError.response?.status === 429;

        if (is429Error) {
          consecutiveErrors += 1;
          currentInterval = Math.min(currentInterval * 2, maxInterval);
        } else {
          consecutiveErrors = 0;
          currentInterval = interval;
        }

        setError(err as Error);
        setIsPolling(false);

        if (consecutiveErrors < 10) {
          pollTimeout = setTimeout(poll, currentInterval);
        }
      }
    };

    poll();

    return () => {
      isMounted = false;
      clearTimeout(pollTimeout);
      setIsPolling(false);
    };
  }, [paymentId, interval, maxInterval, onSuccess, onFailure, enabled]);

  return { payment, error, isPolling };
}

