     3→
     4→export class CreateNOWPaymentsCheckoutSessionDto {
     5→  @ApiProperty({
     6→    description: 'Payment ID to create checkout session for',
     7→    example: '123e4567-e89b-12d3-a456-426614174000',
     8→  })
     9→  @IsString()
    10→  @IsNotEmpty()
    11→  paymentId: string;
    12→
    13→  @ApiProperty({
    14→    description:
    15→      'Cryptocurrency to accept payment in (e.g., btc, eth, usdttrc20). Must be lowercase. Defaults to btc if not specified.',
    16→    example: 'btc',
    17→    required: false,
    18→  })
    19→  @IsString()
    20→  @IsOptional()
    21→  payCurrency?: string;
    22→}
    23→
    24→export class NOWPaymentsCheckoutSessionResponseDto {
    25→  @ApiProperty({
    26→    description: 'NOWPayments payment ID',
    27→    example: '12345',
    28→  })
    29→  paymentId: string;
