import {
  BadRequestException,
  Injectable,
  Logger,
  NotFoundException,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { TransactionHost } from '@nestjs-cls/transactional';

import { PaymentEntity, PaymentMethod, PaymentStatus } from '@/db';
import { TransactionalAdapterTypeOrm } from '@/modules/global';

import {
  CreatePaymentRequest,
  NOWPaymentsService,
} from './nowpayments.service';

/**
 * Service for creating and managing NOWPayments Checkout Sessions.
 * Handles payment flow from payment creation through NOWPayments completion.
 *
 * NOWPayments supports crypto payments (BTC, ETH, USDT, etc).
 * User gets a payment address to send funds to.
 */
@Injectable()
export class NOWPaymentsCheckoutService {
  private readonly logger = new Logger(NOWPaymentsCheckoutService.name);

  constructor(
    private readonly nowpaymentsService: NOWPaymentsService,
    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    private readonly configService: ConfigService,
  ) {}

  /**
   * Create a NOWPayments Checkout Session for a payment.
   * Generates a payment request with crypto address for user to send funds to.
   *
   * @param userId - User ID (for ownership validation)
   * @param paymentId - Payment entity ID
   * @param payCurrency - Cryptocurrency to accept (e.g., 'BTC', 'ETH', 'USDT')
   * @returns Checkout session with payment address and payment ID
   */
  async createCheckoutSession(
    userId: string,
    paymentId: string,
    payCurrency: string = 'usdttrc20',
  ): Promise<{
    paymentAddress: string;
    paymentId: number;
    currency: string;
    payAmount: number;
    payCurrency: string;
    priceAmount: number;
    priceCurrency: string;
  }> {
    return this.txHost.withTransaction(async () => {
      const paymentRepository = this.txHost.tx.getRepository(PaymentEntity);

      const payment = await paymentRepository.findOne({
        where: { id: paymentId },
        relations: ['user'],
      });

      if (!payment) {
        throw new NotFoundException('Payment not found');
      }

      if (payment.userId !== userId) {
        throw new NotFoundException('Payment not found');
      }

      if (payment.status !== PaymentStatus.Created) {
        throw new BadRequestException(
          `Cannot create checkout session for payment in ${payment.status} status`,
        );
      }

      if (payment.expiresAt && payment.expiresAt < new Date()) {
        throw new BadRequestException('Payment has expired');
      }

      if (payment.method !== PaymentMethod.NowPaymentsCrypto) {
        throw new BadRequestException(
          'Payment method must be crypto for NOWPayments',
        );
      }

      const nowpaymentsIpnUrl = this.configService.get<string>(
        'NOWPAYMENTS_IPN_URL',
      );

      const ipnCallbackUrl = `${nowpaymentsIpnUrl}/internal/nowpayments-webhook`;

      const payCurrencyLower = payCurrency.toLowerCase();
      const priceCurrency = payment.currency.toLowerCase();
      const priceAmount = payment.amountTotal / 100;

      try {
        const availableCurrencies =
          await this.nowpaymentsService.getCurrencies();
        if (!availableCurrencies.includes(payCurrencyLower)) {
          this.logger.warn(
            `Currency ${payCurrencyLower} not available in NOWPayments. Available: ${availableCurrencies.join(', ')}`,
          );
          throw new BadRequestException(
            `Cryptocurrency ${payCurrencyLower} is not available. Please choose from: ${availableCurrencies.join(', ')}`,
          );
        }
      } catch (error) {
        if (error instanceof BadRequestException) {
          throw error;
        }
        const errorMessage =
          error instanceof Error ? error.message : String(error);
        this.logger.warn(
          `Failed to validate currencies, proceeding anyway: ${errorMessage}`,
        );
      }

      const createPaymentRequest: CreatePaymentRequest = {
        price_amount: priceAmount,
        price_currency: priceCurrency,
        pay_currency: payCurrencyLower,
        ipn_callback_url: ipnCallbackUrl,
        order_id: payment.id,
        order_description: `Payment for ${payment.purpose}`,
      };

      this.logger.log(
        `Creating NOWPayments payment with data: ${JSON.stringify(createPaymentRequest)}`,
      );

      let nowPayment: Awaited<
        ReturnType<typeof this.nowpaymentsService.createPayment>
      >;
      try {
        nowPayment =
          await this.nowpaymentsService.createPayment(createPaymentRequest);
      } catch (error) {
        const errorMessage =
          error instanceof Error ? error.message : String(error);
        this.logger.warn(
          `Failed to create NOWPayments payment with floating rate: ${errorMessage}. Retrying with fixed rate...`,
        );

        const fixedRateRequest: CreatePaymentRequest = {
          ...createPaymentRequest,
          is_fixed_rate: true,
          is_fee_paid_by_user: true,
        };

        nowPayment =
          await this.nowpaymentsService.createPayment(fixedRateRequest);
      }

      this.logger.log(
        `Created NOWPayments Checkout Session: ${nowPayment.payment_id} for payment: ${payment.id}`,
      );

      payment.status = PaymentStatus.Pending;
      payment.providerRef = String(nowPayment.payment_id);
      payment.metadata = {
        ...payment.metadata,
        nowpaymentsPaymentId: nowPayment.payment_id,
        payCurrency: nowPayment.pay_currency,
        payAddress: nowPayment.pay_address,
      };
      await paymentRepository.save(payment);

      return {
        paymentAddress: nowPayment.pay_address,
        paymentId: nowPayment.payment_id,
        currency: nowPayment.pay_currency,
        payAmount: nowPayment.pay_amount,
        payCurrency: nowPayment.pay_currency,
        priceAmount: nowPayment.price_amount,
        priceCurrency: nowPayment.price_currency,
      };
    });
  }

  /**
   * Get payment status from NOWPayments.
   * Can be called to check if payment has been received.
   *
   * @param paymentId - Payment entity ID
   * @param userId - User ID (for ownership validation)
   * @returns Payment status and details
   */
  async getPaymentStatus(
    paymentId: string,
    userId: string,
  ): Promise<{
    status: string;
    amountReceived: number;
    confirmations: number;
  }> {
    return this.txHost.withTransaction(async () => {
      const paymentRepository = this.txHost.tx.getRepository(PaymentEntity);

      const payment = await paymentRepository.findOne({
        where: { id: paymentId },
      });

      if (!payment) {
        throw new NotFoundException('Payment not found');
      }

      if (payment.userId !== userId) {
        throw new NotFoundException('Payment not found');
      }

      if (!payment.providerRef) {
        throw new BadRequestException(
          'Payment does not have NOWPayments reference',
        );
      }

      const nowPayment = await this.nowpaymentsService.getPayment(
        parseInt(payment.providerRef, 10),
      );

      return {
        status: nowPayment.payment_status,
        amountReceived: nowPayment.pay_amount,
        confirmations: 0,
      };
    });
  }
}

