/**
 * NOWPayments API Response Types
 * Complete type definitions for all API endpoints
 */

/**
 * Payment creation response from NOWPayments API
 */
export interface NOWPaymentsPaymentResponse {
  payment_id: number;
  payment_status: string;
  pay_address: string;
  pay_amount: number;
  pay_currency: string;
  price_amount: number;
  price_currency: string;
  order_id?: string;
  order_description?: string;
  ipn_callback_url: string;
  created_at: string;
  updated_at: string;
  is_fixed_rate: boolean;
  is_fee_paid_by_user: boolean;
  tx_hash?: string;
  confirmations?: number;
  actually_paid?: number;
  actually_paid_at_fiat?: number;
  outcome_amount?: number;
  outcome_currency?: string;
  network_fee?: number;
  burning_percent?: number;
  type?: string;
  payin_extra_id?: string | null;
  error_msg?: string;
}

/**
 * Payout (withdrawal) response from NOWPayments API
 * Supports both response formats
 */
export interface NOWPaymentsPayoutResponse {
  id: number;
  batch_withdrawal_id?: string | number;
  walletAddress?: string; // Format 1
  address?: string; // Format 2
  amount: number | string;
  currency: string;
  status: string;
  txid?: string | null;
  hash?: string | null; // Alternative hash field
  fee?: string | number | null;
  extra_id?: string | null;
  ipn_callback_url?: string;
  error?: string | null;
  created_at: string;
  requested_at?: string | null;
  updated_at: string | null;
}

export interface NOWPaymentsPayoutWithdrawalRequest {
  address: string;
  currency: string;
  amount: number;
  extra_id?: string;
  ipn_callback_url?: string;
  payout_description?: string;
  unique_external_id?: string;
  fiat_amount?: number;
  fiat_currency?: string;
}

export interface NOWPaymentsCreatePayoutRequest {
  payout_description?: string;
  ipn_callback_url?: string;
  withdrawals: NOWPaymentsPayoutWithdrawalRequest[];
}

export interface NOWPaymentsCreatePayoutResponse {
  id: string | number;
  withdrawals: Array<{
    is_request_payouts?: boolean;
    id: string | number;
    address: string;
    currency: string;
    amount: string | number;
    batch_withdrawal_id?: string | number;
    ipn_callback_url?: string;
    status?: string;
    extra_id?: string | null;
    hash?: string | null;
    error?: string | null;
    payout_description?: string | null;
    unique_external_id?: string | null;
    created_at?: string;
    requested_at?: string | null;
    updated_at?: string | null;
    fiat_amount?: string | number;
    fiat_currency?: string;
  }>;
}

/**
 * Checkout session data for client
 */
export interface NOWPaymentsCheckoutSession {
  paymentAddress: string;
  paymentId: number;
  currency: string;
  amount: number;
  priceAmount: number;
  priceCurrency: string;
  expiresAt?: Date;
}

/**
 * Payment webhook payload (deposit)
 * Includes all possible fields from NOWPayments IPN
 */
export interface NOWPaymentsPaymentWebhookPayload {
  payment_id: number;
  parent_payment_id?: number;
  invoice_id?: string | null;
  payment_status: string;
  pay_address: string;
  payin_extra_id?: string | null;
  price_amount: number;
  price_currency: string;
  pay_amount: number;
  actually_paid?: number;
  actually_paid_at_fiat?: number;
  pay_currency: string;
  order_id?: string | null;
  order_description?: string | null;
  purchase_id?: string;
  outcome_amount?: number;
  outcome_currency?: string;
  payment_extra_ids?: string | null;
  ipn_callback_url?: string;
  created_at?: string;
  updated_at?: string;
  is_fixed_rate?: boolean;
  is_fee_paid_by_user?: boolean;
  tx_hash?: string;
  payin_hash?: string;
  outcome_hash?: string;
  confirmations?: number;
  network_fee?: number;
  service_fee?: number;
  error_msg?: string;
}

/**
 * Payout webhook payload (withdrawal)
 * Supports both NOWPayments formats
 */
export interface NOWPaymentsPayoutWebhookPayload {
  // Format 1 fields
  payout_id?: number;
  payout_status?: string;
  wallet_address?: string;

  // Format 2 fields (alternative)
  id?: string | number;
  status?: string;
  address?: string;

  // Common fields
  batch_withdrawal_id?: string | number;
  amount: number | string;
  currency: string;
  fee?: string | number | null;
  extra_id?: string | null;

  // Transaction hash (multiple formats)
  txid?: string | null;
  hash?: string | null;
  tx_hash?: string | null;

  // Error fields
  error_msg?: string | null;
  error?: string | null;

  // Timestamps
  created_at?: string;
  requested_at?: string | null;
  updated_at?: string | null;

  // Callback
  ipn_callback_url?: string;
}

/**
 * Unified webhook payload supporting both payment and payout
 */
export type NOWPaymentsWebhookPayload =
  | NOWPaymentsPaymentWebhookPayload
  | NOWPaymentsPayoutWebhookPayload;

/**
