import { ApiProperty } from '@nestjs/swagger';
import { IsNotEmpty, IsOptional, IsString } from 'class-validator';

export class CreateNOWPaymentsCheckoutSessionDto {
  @ApiProperty({
    description: 'Payment ID to create checkout session for',
    example: '123e4567-e89b-12d3-a456-426614174000',
  })
  @IsString()
  @IsNotEmpty()
  paymentId: string;

  @ApiProperty({
    description:
      'Cryptocurrency to accept payment in (e.g., btc, eth, usdttrc20). Must be lowercase. Defaults to btc if not specified.',
    example: 'btc',
    required: false,
  })
  @IsString()
  @IsOptional()
  payCurrency?: string;
}

export class NOWPaymentsCheckoutSessionResponseDto {
  @ApiProperty({
    description: 'NOWPayments payment ID',
    example: '12345',
  })
  paymentId: string;

  @ApiProperty({
    description: 'Blockchain address to send payment to',
    example: '1A1z7agoat2PbfVoevcAaxVQnRS8nqJjF',
  })
  payAddress: string;

  @ApiProperty({
    description: 'Amount to send in the specified cryptocurrency',
    example: 0.00234,
  })
  payAmount: number;

  @ApiProperty({
    description: 'Cryptocurrency to send',
    example: 'usdttrc20',
  })
  payCurrency: string;

  @ApiProperty({
    description: 'Original price amount',
    example: 100.0,
  })
  priceAmount: number;

  @ApiProperty({
    description: 'Original price currency',
    example: 'USD',
  })
  priceCurrency: string;

  @ApiProperty({
    description: 'Direct payment link (optional, NOWPayments hosted page)',
    example: 'https://nowpayments.io/payment/?iid=12345',
    required: false,
  })
  paymentLink?: string;
}

export class NOWPaymentsPaymentStatusResponseDto {
  @ApiProperty({
    description: 'Current payment status',
    example: 'finished',
  })
  status: string;

  @ApiProperty({
    description: 'Amount received in crypto',
    example: 0.00234,
  })
  amountReceived: number;

  @ApiProperty({
