                fill="none"
                viewBox="0 0 24 24"
                aria-hidden="true"
              >
                <circle
                  className="opacity-25"
                  cx="12"
                  cy="12"
                  r="10"
                  stroke="currentColor"
                  strokeWidth="4"
                />
                <path
                  className="opacity-75"
                  fill="currentColor"
                  d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
                />
              </svg>
            </div>
          )}

          {phase === "failed" && (
            <div className="flex items-center gap-1.5">
              <span className="font-medium font-new-sans text-red-600 text-xs">
                Payment Rejected
              </span>
              <svg
                width="14"
                height="14"
                viewBox="0 0 24 24"
                fill="none"
                aria-hidden="true"
              >
                <path
                  d="M6 6l12 12M6 18L18 6"
                  stroke="#dc2626"
                  strokeWidth="2.5"
                  strokeLinecap="round"
                />
              </svg>
            </div>
          )}
        </div>

        {phase === "failed" && (
          <div className="flex gap-3 rounded-xl border border-red-200 bg-red-50 p-4">
            <svg
              width="20"
              height="20"
              viewBox="0 0 24 24"
              fill="none"
