              >
                <input
                  type="radio"
                  name="payment-method"
                  className="sr-only"
                  checked={
                    selectedMethod.type === "paypal-saved" &&
                    selectedMethod.id === method.id
                  }
                  onChange={() =>
                    setSelectedMethod({
                      type: "paypal-saved",
                      id: method.id,
                      email: method.email,
                    })
